import "../styles/Team.css";
import { FaLinkedin, FaGithub } from "react-icons/fa";

const teamMembers = [
  {
    name: "Anupam Sanfui",
    role: "Cyber Security Analyst",
    imgSrc: "/images/anupam.jpg",
    linkedin: "#",
  },
  {
    name: "Sayan Maity",
    role: "Advanced Data Analytics & ML Intern",
    imgSrc: "/images/sayan.jpg",
    linkedin: "#",
    github: "#",
  },
  {
    name: "Rupankar Garai",
    role: "Freelancer with 2 years of experience || Intern at Edunet Foundation || Tech Adventure ||",
    imgSrc: "/images/rupankar.jpg",
    linkedin: "#",
    github: "#",
  },
  // Add more team members as needed
];

export default function Team() {
  return (
    <section className="team-section">
      <h2>Our Team</h2>
      <p>
        Meet our talented team of professionals dedicated to delivering exceptional solutions.
      </p>

      <div className="team-carousel">
        {teamMembers.map((member, idx) => (
          <div className="team-card" key={idx}>
            <div className="image-container">
              <img src={member.imgSrc} alt={member.name} />
            </div>
            <h3>{member.name}</h3>
            <p className="role">{member.role}</p>
            <div className="social-icons">
              {member.linkedin && (
                <a href={member.linkedin} target="_blank" rel="noopener noreferrer">
                  <FaLinkedin />
                </a>
              )}
              {member.github && (
                <a href={member.github} target="_blank" rel="noopener noreferrer">
                  <FaGithub />
                </a>
              )}
            </div>
          </div>
        ))}
      </div>

      <div className="carousel-nav">
        <button>Previous</button>
        <div className="dots">
          <span className="dot active"></span>
          <span className="dot"></span>
          <span className="dot"></span>
        </div>
        <button>Next</button>
      </div>
    </section>
  );
}
